styles:
.subheading {
text-transform: uppercase;
color: var(--green-700);
font-size: 15px;
font-weight: 600;
display: flex;
align-items: center;
gap: 10px;
}
.subheading::before {
  content: '';
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--green-700);
  box-shadow: 0 0 0 4px var(--green-50);
}
